        }
    }
}

#[doc(hidden)]
pub fn write_error_default(req: &Request, res: &mut Response, footer: Option<&str>) {
    let format = guess_accept_mime(req, None);
    let (format, data) = if let ResBody::Error(body) = &res.body {
        status_error_bytes(body, &format, footer)
    } else {
        let status = res.status_code.unwrap_or(StatusCode::NOT_FOUND);
        status_error_bytes(
            &StatusError::from_code(status).unwrap_or_else(StatusError::internal_server_error),
            &format,
            footer,
        )
    };
    let content_type = format
        .to_string()
        .parse()
        .unwrap_or_else(|_| header::HeaderValue::from_static("text/plain; charset=utf-8"));
    res.headers_mut().insert(header::CONTENT_TYPE, content_type);
    let _ = res.write_body(data);
}

impl<'a> ContextBase<'a, &'a Positioned<Field>> {
#[doc(hidden)]
pub fn param_value<T: InputType>(
    &self,
    name: &str,
    default: Option<fn() -> T>,
) -> ServerResult<(Pos, T)> {
    self.get_param_value(&self.item.node.arguments, name, default)
}

#[doc(hidden)]
pub fn oneof_param_value<T: OneofObjectType>(&self) -> ServerResult<(Pos, T)> {
    use indexmap::IndexMap;

    let mut map = IndexMap::new();

    for (name, value) in &self.item.node.arguments {
        // Skip omitted variable-backed arguments so input objects can observe
        // `Undefined`.
        if let Some(value) = self.resolve_input_value(value.clone())? {
            map.insert(name.node.clone(), value);
        }
    }

    InputType::parse(Some(Value::Object(map)))
        .map(|value| (self.item.pos, value))
        .map_err(|e| e.into_server_error(self.item.pos))
}

#[doc(hidden)]
    pub fn strip_to_hyper<QB>(&mut self) -> Result<hyper::Request<QB>, crate::Error>
    where
        QB: TryFrom<ReqBody>,
        <QB as TryFrom<ReqBody>>::Error: StdError + Send + Sync + 'static,
    {
        let mut builder = http::request::Builder::new()
            .method(self.method.clone())
            .uri(self.uri.clone())
            .version(self.version);
        if let Some(headers) = builder.headers_mut() {
            *headers = std::mem::take(&mut self.headers);
        }
        if let Some(extensions) = builder.extensions_mut() {
            *extensions = std::mem::take(&mut self.extensions);
        }

        std::mem::take(&mut self.body)
            .try_into()
            .map_err(crate::Error::other)
            .and_then(|body| builder.body(body).map_err(crate::Error::other))
    }
